"""Utilities for text file processing."""

from __future__ import annotations

import os
import shutil
import subprocess


def sort_and_uniq_by_column(input_file: str, column: int, output_file: str) -> None:
    """
    Sort a text file by a specified column and remove duplicate lines.

    This function invokes the external ``sort`` and ``uniq`` commands using
    ``subprocess.Popen`` without a shell for improved security.

    The sort is performed using a 1-based column index. Duplicate removal is
    then applied to the sorted output.

    Args:
        input_file: Path to the input text file.
        column: 1-based column number to sort by.
        output_file: Path to the output file.

    Raises:
        ValueError: If ``column`` is less than 1.
        FileNotFoundError: If the input file does not exist, or if required
            system commands are unavailable.
        OSError: If file handling fails.
        RuntimeError: If the external commands fail.
    """
    if not isinstance(input_file, str) or not input_file:
        raise ValueError("input_file must be a non-empty string")
    if not isinstance(output_file, str) or not output_file:
        raise ValueError("output_file must be a non-empty string")
    if not isinstance(column, int) or column < 1:
        raise ValueError("column must be an integer greater than or equal to 1")

    if not os.path.isfile(input_file):
        raise FileNotFoundError(f"Input file does not exist: {input_file}")

    sort_path = shutil.which("sort")
    uniq_path = shutil.which("uniq")

    if sort_path is None:
        raise FileNotFoundError("Required command not found: sort")
    if uniq_path is None:
        raise FileNotFoundError("Required command not found: uniq")

    sort_proc = None
    uniq_proc = None

    try:
        with open(input_file, "rb") as in_f, open(output_file, "wb") as out_f:
            sort_proc = subprocess.Popen(
                [sort_path, "-k", f"{column},{column}", input_file],
                stdout=subprocess.PIPE,
                stderr=subprocess.PIPE,
            )

            uniq_proc = subprocess.Popen(
                [uniq_path],
                stdin=sort_proc.stdout,
                stdout=out_f,
                stderr=subprocess.PIPE,
            )

            if sort_proc.stdout is not None:
                sort_proc.stdout.close()

            uniq_stderr = b""
            if uniq_proc.stderr is not None:
                uniq_stderr = uniq_proc.stderr.read()

            sort_stderr = b""
            if sort_proc.stderr is not None:
                sort_stderr = sort_proc.stderr.read()

            uniq_returncode = uniq_proc.wait()
            sort_returncode = sort_proc.wait()

            if sort_returncode != 0:
                raise RuntimeError(
                    f"sort command failed with exit code {sort_returncode}: "
                    f"{sort_stderr.decode(errors='replace').strip()}"
                )

            if uniq_returncode != 0:
                raise RuntimeError(
                    f"uniq command failed with exit code {uniq_returncode}: "
                    f"{uniq_stderr.decode(errors='replace').strip()}"
                )

    except Exception:
        try:
            if output_file and os.path.exists(output_file):
                os.remove(output_file)
        except OSError:
            pass
        raise
    finally:
        if sort_proc is not None:
            if sort_proc.stdout is not None:
                sort_proc.stdout.close()
            if sort_proc.stderr is not None:
                sort_proc.stderr.close()
        if uniq_proc is not None:
            if uniq_proc.stderr is not None:
                uniq_proc.stderr.close()
            if uniq_proc.stdout is not None:
                uniq_proc.stdout.close()
